package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"

	"terravault-admission/pkg/config"
	"terravault-admission/pkg/policy"
	admissionv1 "k8s.io/api/admission/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

func main() {
	// Load configuration
	cfg := config.LoadConfig()

	// Setup HTTP server
	mux := http.NewServeMux()
	mux.HandleFunc("/validate", validateHandler)

	// Create TLS config
	certFile := os.Getenv("TLS_CERT_FILE")
	keyFile := os.Getenv("TLS_KEY_FILE")

	if certFile == "" || keyFile == "" {
		log.Fatal("TLS_CERT_FILE and TLS_KEY_FILE must be set")
	}

	addr := fmt.Sprintf(":%s", cfg.Port)
	log.Printf("Starting Terravault admission webhook on %s", addr)

	// Start server with TLS
	server := &http.Server{
		Addr:    addr,
		Handler: mux,
	}

	if err := server.ListenAndServeTLS(certFile, keyFile); err != nil {
		log.Fatalf("Failed to start webhook server: %v", err)
	}
}

// validateHandler handles admission webhook requests
func validateHandler(w http.ResponseWriter, r *http.Request) {
	// Only accept POST requests
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Decode AdmissionReview request
	var admissionReview admissionv1.AdmissionReview
	if err := json.NewDecoder(r.Body).Decode(&admissionReview); err != nil {
		log.Printf("Error decoding AdmissionReview: %v", err)
		http.Error(w, "Invalid request body", http.StatusBadRequest)
		return
	}

	// Validate admission request type
	if admissionReview.Request == nil {
		log.Printf("Error: AdmissionReview request is nil")
		http.Error(w, "Invalid AdmissionReview", http.StatusBadRequest)
		return
	}

	// Handle the admission request
	response := handleAdmissionRequest(admissionReview.Request)

	// Create response AdmissionReview
	admissionReviewResponse := admissionv1.AdmissionReview{
		TypeMeta: metav1.TypeMeta{
			Kind:       admissionReview.Kind,
			APIVersion: admissionReview.APIVersion,
		},
		Response: response,
	}

	// Set response Content-Type
	w.Header().Set("Content-Type", "application/json")

	// Encode and send response
	if err := json.NewEncoder(w).Encode(admissionReviewResponse); err != nil {
		log.Printf("Error encoding AdmissionResponse: %v", err)
		http.Error(w, "Failed to encode response", http.StatusInternalServerError)
		return
	}

	log.Printf("Admission decision: allowed=%v for pod %s/%s", response.Allowed,
		admissionReview.Request.Namespace, admissionReview.Request.Name)
}

// handleAdmissionRequest processes an admission request and applies policy validation
func handleAdmissionRequest(req *admissionv1.AdmissionRequest) *admissionv1.AdmissionResponse {
	// Create a new AdmissionReview with just the request part
	admissionReview := &admissionv1.AdmissionReview{
		TypeMeta: metav1.TypeMeta{
			Kind:       req.Kind,
			APIVersion: req.APIVersion,
		},
		Request: req,
	}

	// Validate the pod using the policy validator
	response := policy.ValidatePod(admissionReview)

	// Log the result
	if response.Allowed {
		log.Printf("Allowed admission for pod %s/%s in namespace %s", req.Name, req.Namespace, req.Namespace)
	} else {
		log.Printf("Denied admission for pod %s/%s in namespace %s. Reason: %s", req.Name, req.Namespace, req.Namespace,
			response.Result.Message)
		for _, cause := range response.Result.Details.Causes {
			log.Printf("  - %s", cause.Message)
		}
	}

	return response
}

// For backward compatibility with the test serde package
var serde = runtimeSerde{}

// runtimeSerde provides simple serialization/deserialization for testing
type runtimeSerde struct{}

func (runtimeSerde) Decode(data []byte, obj interface{}) error {
	return json.Unmarshal(data, obj)
}

func (runtimeSerde) Encode(obj interface{}) ([]byte, error) {
	return json.Marshal(obj)
}

